// Track Claude API usage from n8n execution history
// This runs hourly to aggregate costs
const now = new Date();
const hour = now.toISOString().slice(0, 13);

// Estimate costs based on n8n execution count
// Claude Sonnet: ~$3/M input tokens, $15/M output tokens
// Average workflow: ~500 input + 300 output tokens
const estimatedCostPerCall = 0.006; // ~$0.006 per Claude call

// Get execution count from env or default
const dailyBudget = parseFloat($env.CLAUDE_DAILY_BUDGET_USD || '5.00');

const report = {
  timestamp: now.toISOString(),
  hour: hour,
  estimated_cost_per_call: estimatedCostPerCall,
  daily_budget_usd: dailyBudget,
  note: 'Actual costs tracked via Anthropic dashboard. This is an estimate.'
};

return [{ json: report }];

// Budget check: estimate daily spend and warn if exceeded
const report = $('Calculate Costs').first().json;
const now = new Date();
const hoursElapsed = now.getUTCHours() + 1; // hours passed today

// Estimate based on active workflows with Claude calls:
// - LinkedIn: 1/week (Thu) = ~0.14/day
// - Medium: 1/week (Sat) = ~0.14/day
// - YouTube: 1/week (Sun) = ~0.14/day
// - Quora: 1/day
// - Discord: 0 (no Claude calls)
// - Twitter workflows: ~4/day (from existing workflows)
// - Reddit: ~1/day (from existing workflows)
// - Telegram: ~3/day (from existing workflows)
const estimatedDailyClaudeCalls = 4 + 1 + 3 + 1 + 0.14 + 0.14 + 0.14; // ~9.42 calls/day
const estimatedDailyCost = estimatedDailyClaudeCalls * report.estimated_cost_per_call;
const projectedDailyCost = (estimatedDailyCost / 24) * 24; // full day projection

const budgetUsedPct = (estimatedDailyCost / report.daily_budget_usd) * 100;
const isOverBudget = estimatedDailyCost > report.daily_budget_usd;
const isNearBudget = budgetUsedPct > 80;

const budgetReport = {
  timestamp: now.toISOString(),
  hours_elapsed_today: hoursElapsed,
  estimated_daily_claude_calls: Math.round(estimatedDailyClaudeCalls),
  estimated_daily_cost_usd: parseFloat(estimatedDailyCost.toFixed(4)),
  projected_daily_cost_usd: parseFloat(projectedDailyCost.toFixed(4)),
  daily_budget_usd: report.daily_budget_usd,
  budget_used_pct: parseFloat(budgetUsedPct.toFixed(1)),
  status: isOverBudget ? 'OVER_BUDGET' : isNearBudget ? 'NEAR_BUDGET' : 'OK',
  warning: isOverBudget
    ? `Daily estimated cost ($${estimatedDailyCost.toFixed(2)}) EXCEEDS budget ($${report.daily_budget_usd.toFixed(2)}). Consider reducing frequency or pausing non-critical workflows.`
    : isNearBudget
    ? `Daily estimated cost ($${estimatedDailyCost.toFixed(2)}) is approaching budget ($${report.daily_budget_usd.toFixed(2)}). Monitor closely.`
    : `Budget healthy. Estimated $${estimatedDailyCost.toFixed(2)} of $${report.daily_budget_usd.toFixed(2)} daily budget.`
};

console.log(`[${now.toISOString()}] Budget status: ${budgetReport.status} - ${budgetReport.warning}`);

return [{ json: budgetReport }];

